mapper.update:
update kh_user_email_token
set due_time = #{dueTime,jdbcType=TIMESTAMP}, update_time = now()
where id = #{id,jdbcType=BIGINT}

update kh_user_email_token
set status = #{status,jdbcType=SMALLINT}, update_time = now()
where id = #{id,jdbcType=BIGINT}

mapper.select:
select id, user_id, email, token_type, token, status, due_time, create_time, update_time
from kh_user_email_token
where token = #{token,jdbcType=VARCHAR}

select id, user_id, email, token_type, token, status, due_time, create_time, update_time
from kh_user_email_token
where email = #{email,jdbcType=VARCHAR}
and token_type = #{tokenType,jdbcType=SMALLINT}
order by create_time desc limit 1
